import{_ as e,o as i,c as t,a2 as l}from"./chunks/framework.D6hBiDio.js";const h=JSON.parse('{"title":"LuCI Web UI","description":"Graphical management of Tailscale via luci-app-tailscale-community","frontmatter":{"title":"LuCI Web UI","description":"Graphical management of Tailscale via luci-app-tailscale-community"},"headers":[],"relativePath":"en/guide/luci.md","filePath":"en/guide/luci.md","lastUpdated":1784575673000}'),o={name:"en/guide/luci.md"};function r(s,a,n,c,u,p){return i(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="luci-web-ui" tabindex="-1">LuCI Web UI <a class="header-anchor" href="#luci-web-ui" aria-label="Permalink to &quot;LuCI Web UI&quot;">​</a></h1><p>For a graphical interface to manage Tailscale, we recommend installing the LuCI app built by <a href="https://github.com/Tokisaki-Galaxy" target="_blank" rel="noreferrer">@Tokisaki-Galaxy</a>.</p><h2 id="luci-app-tailscale-community" tabindex="-1">luci-app-tailscale-community <a class="header-anchor" href="#luci-app-tailscale-community" aria-label="Permalink to &quot;luci-app-tailscale-community&quot;">​</a></h2><p>This is an open-source LuCI application that provides an easy-to-use web interface to configure and manage Tailscale directly from OpenWrt&#39;s LuCI dashboard.</p><ul><li><strong>Repository</strong>: <a href="https://github.com/Tokisaki-Galaxy/luci-app-tailscale-community" target="_blank" rel="noreferrer">Tokisaki-Galaxy/luci-app-tailscale-community</a></li></ul><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><ul><li>View Tailscale status and connection info</li><li>Manage Tailscale settings through LuCI</li><li>Start/stop/restart the Tailscale service</li><li>Monitor connected peers</li><li>Configure routes and exit nodes</li></ul><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><p>Follow the instructions in the <a href="https://github.com/Tokisaki-Galaxy/luci-app-tailscale-community" target="_blank" rel="noreferrer">luci-app-tailscale-community repository</a> to install the LuCI app on your OpenWrt device.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The LuCI app works with the smaller Tailscale package from this repository — they are fully compatible.</p></div>',10)])])}const d=e(o,[["render",r]]);export{h as __pageData,d as default};
